import { describe, expect, test, vi } from "vitest";
import { useElementScreenshot } from "./use-element-screenshot";

vi.mock("html-to-image", () => ({
	toPng: vi.fn(),
}));

import { toPng } from "html-to-image";
const mockToPng = vi.mocked(toPng);

describe("useElementScreenshot", () => {
	test("returns a capture function", () => {
		const { result } = renderHook(() => useElementScreenshot(null));

		expect(result.current.capture).toBeTypeOf("function");
	});

	test("capture() with null element throws a meaningful error", async () => {
		const { result } = renderHook(() => useElementScreenshot(null));

		await expect(result.current.capture()).rejects.toThrow(
			"No element provided for screenshot capture",
		);
	});

	test("capture() calls toPng with correct options (width capped at 800, pixelRatio: 1)", async () => {
		const fakeElement = {
			scrollWidth: 1200,
		} as HTMLElement;

		mockToPng.mockResolvedValue("data:image/png;base64,abc123");

		const { result } = renderHook(() => useElementScreenshot(fakeElement));
		await result.current.capture();

		expect(mockToPng).toHaveBeenCalledWith(fakeElement, {
			width: 800,
			pixelRatio: 1,
			cacheBust: true,
		});
	});

	test("capture() uses element scrollWidth when under 800px", async () => {
		const fakeElement = {
			scrollWidth: 500,
		} as HTMLElement;

		mockToPng.mockResolvedValue("data:image/png;base64,abc123");

		const { result } = renderHook(() => useElementScreenshot(fakeElement));
		await result.current.capture();

		expect(mockToPng).toHaveBeenCalledWith(fakeElement, {
			width: 500,
			pixelRatio: 1,
			cacheBust: true,
		});
	});

	test("capture() returns base64 string without data URL prefix", async () => {
		const fakeElement = {
			scrollWidth: 600,
		} as HTMLElement;

		mockToPng.mockResolvedValue("data:image/png;base64,SGVsbG8gV29ybGQ=");

		const { result } = renderHook(() => useElementScreenshot(fakeElement));
		const base64 = await result.current.capture();

		expect(base64).toBe("SGVsbG8gV29ybGQ=");
	});
});

import { afterEach, describe, expect, test, vi } from "vitest";
import { requestClaudeResponse } from "./claude-client";
import type { ClaudeRequest } from "./claude-client";

vi.mock("@anthropic-ai/sdk", () => {
  const mockCreate = vi.fn();
  return {
    default: vi.fn().mockImplementation(() => ({
      messages: { create: mockCreate },
    })),
    __mockCreate: mockCreate,
  };
});

async function getMockCreate() {
  const mod = await import("@anthropic-ai/sdk");
  return (mod as unknown as { __mockCreate: ReturnType<typeof vi.fn> })
    .__mockCreate;
}

async function getMockConstructor() {
  const mod = await import("@anthropic-ai/sdk");
  return mod.default as unknown as ReturnType<typeof vi.fn>;
}

describe("requestClaudeResponse", () => {
  afterEach(() => {
    vi.clearAllMocks();
  });

  const baseRequest: ClaudeRequest = {
    model: "claude-sonnet-4-6-20250514",
    system: "You are a helpful assistant.",
    messages: [{ role: "user", content: [{ type: "text", text: "Hello" }] }],
    max_tokens: 1024,
  };

  const mockApiResponse = {
    id: "msg_test123",
    content: [{ type: "text", text: "Hello back!" }],
    stop_reason: "end_turn",
    model: "claude-sonnet-4-6-20250514",
    usage: { input_tokens: 10, output_tokens: 5 },
  };

  test("creates Anthropic client with correct API key", async () => {
    const mockCreate = await getMockCreate();
    mockCreate.mockResolvedValue(mockApiResponse);
    const MockConstructor = await getMockConstructor();

    await requestClaudeResponse(baseRequest, {
      apiKey: "sk-ant-test-key",
      timeoutMs: 30000,
    });

    expect(MockConstructor).toHaveBeenCalledWith({
      apiKey: "sk-ant-test-key",
    });
  });

  test("sends correctly formatted request to messages.create", async () => {
    const mockCreate = await getMockCreate();
    mockCreate.mockResolvedValue(mockApiResponse);

    await requestClaudeResponse(baseRequest, {
      apiKey: "sk-ant-test-key",
      timeoutMs: 30000,
    });

    expect(mockCreate).toHaveBeenCalledWith(
      expect.objectContaining({
        model: "claude-sonnet-4-6-20250514",
        system: "You are a helpful assistant.",
        messages: baseRequest.messages,
        max_tokens: 1024,
      }),
      expect.objectContaining({ timeout: 30000 }),
    );
  });

  test("passes tools and tool_choice when provided", async () => {
    const mockCreate = await getMockCreate();
    mockCreate.mockResolvedValue(mockApiResponse);

    const requestWithTools: ClaudeRequest = {
      ...baseRequest,
      tools: [
        {
          name: "test_tool",
          description: "A test tool",
          input_schema: { type: "object", properties: {} },
        },
      ],
      tool_choice: { type: "auto" },
    };

    await requestClaudeResponse(requestWithTools, {
      apiKey: "sk-ant-test-key",
      timeoutMs: 30000,
    });

    expect(mockCreate).toHaveBeenCalledWith(
      expect.objectContaining({
        tools: requestWithTools.tools,
        tool_choice: { type: "auto" },
      }),
      expect.anything(),
    );
  });

  test("returns correctly shaped response", async () => {
    const mockCreate = await getMockCreate();
    mockCreate.mockResolvedValue(mockApiResponse);

    const result = await requestClaudeResponse(baseRequest, {
      apiKey: "sk-ant-test-key",
      timeoutMs: 30000,
    });

    expect(result).toEqual({
      id: "msg_test123",
      content: [{ type: "text", text: "Hello back!" }],
      stop_reason: "end_turn",
      model: "claude-sonnet-4-6-20250514",
      usage: { input_tokens: 10, output_tokens: 5 },
    });
  });

  test("passes timeout from config", async () => {
    const mockCreate = await getMockCreate();
    mockCreate.mockResolvedValue(mockApiResponse);

    await requestClaudeResponse(baseRequest, {
      apiKey: "sk-ant-key",
      timeoutMs: 60000,
    });

    expect(mockCreate).toHaveBeenCalledWith(
      expect.anything(),
      expect.objectContaining({ timeout: 60000 }),
    );
  });
});

import { toPng } from "html-to-image";

type UseElementScreenshotReturn = {
	capture: () => Promise<string>;
};

export function useElementScreenshot(
	element: HTMLElement | null,
): UseElementScreenshotReturn {
	const capture = async (): Promise<string> => {
		if (!element) {
			throw new Error("No element provided for screenshot capture");
		}

		const dataUrl = await toPng(element, {
			width: Math.min(element.scrollWidth, 800),
			pixelRatio: 1,
			cacheBust: true,
		});

		// Strip the data URL prefix to get raw base64
		const base64 = dataUrl.replace(/^data:image\/png;base64,/, "");
		return base64;
	};

	return { capture };
}

